const Q_GOVERNMENT_1997=[{"id": "objective>Government>1997>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Authority refers to the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">might to secure compliance from others within a given social setting</div>", "<div style=\"font-family:Cambria;font-size:17px;\">power to exercise might over others behaviour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mandate to exercise power over others</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ability to compel others to act in a particular way</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Authority is the mandate to exercise power over others</div>", "topic": "BASIC CONCEPTS OF GOVERNMENT : POWER, AUTHORITY, LEGITIMACY AND SOVEREIGNTY"}, {"id": "objective>Government>1997>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Government is different from other political organizations because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">it has legitimate power over citizens</div>", "<div style=\"font-family:Cambria;font-size:17px;\">its officials have fixed terms of office</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it can punish those who violate its rules</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it is made up of elected officials</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Government is different from other political organizations because it has legitimate power over citizens. This means that the government has the right to make laws and enforce them, and the citizens are obliged to obey these laws. Other political organizations do not have this power.</div>", "topic": "BASIC CONCEPTS OF GOVERNMENT : POWER, AUTHORITY, LEGITIMACY AND SOVEREIGNTY"}, {"id": "objective>Government>1997>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Judicial independence in a modern democracy can be ensured by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the confirmation of the appointment of judges by the legislature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the provision that judges can only be removed from office by the president - in - council</div>", "<div style=\"font-family:Cambria;font-size:17px;\">making judges independent of the ministry of justice</div>", "<div style=\"font-family:Cambria;font-size:17px;\">safeguarding the security of tenure of judges</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Judicial independence in a modern democracy can be ensured by safeguarding the security of tenure of judges. This means that judges cannot be easily removed from their position, which allows them to make decisions without fear of political repercussions. This is a key aspect of the separation of powers, a fundamental principle in democratic governance that prevents any one branch of government (executive, legislative, judicial) from becoming too powerful.</div>", "topic": "ARMS OF GOVERNMENT : JUDICIARY FUNCTIONS, POWERS AND COMPONENTS"}, {"id": "objective>Government>1997>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The official report of proceeding in parliament is known as the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hansard</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diary of events</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gazette</div>", "<div style=\"font-family:Cambria;font-size:17px;\">summary of proceedings</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hansard is the traditional name of the transcripts of Parliamentary Debates in Britain and many Commonwealth countries.</div>", "topic": "ARMS OF GOVERNMENT : LEGISLATURE TYPES, STRUCTURE, FUNCTIONS AND POWERS"}, {"id": "objective>Government>1997>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An important feature of the federal system of government is the existence of a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">strong national legislature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">president with veto power</div>", "<div style=\"font-family:Cambria;font-size:17px;\">court system with impartial judges</div>", "<div style=\"font-family:Cambria;font-size:17px;\">multiple tiers of government</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A federal system of government is characterized by the division of powers between different levels of government such as the national government and the state or provincial governments. Therefore, the existence of multiple tiers of government is an important feature of a federal system.</div>", "topic": "CONSTITUTION : TYPES OF CONSTITUTION"}, {"id": "objective>Government>1997>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An important aspect of an unwritten constitution is that it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">is easy to understand by everbody</div>", "<div style=\"font-family:Cambria;font-size:17px;\">safequards the monarchy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">contains customary laws and conventions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is not easily amended</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An unwritten constitution is one where not all constitutional laws are codified in a single document. It includes statutes, case laws, and conventions. Therefore, it contains customary laws and conventions.</div>", "topic": "CONSTITUTION : TYPES OF CONSTITUTION"}, {"id": "objective>Government>1997>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The ideology that advocates the complete control of the sources of power is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> totalitarianism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">socialism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">liberalism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">democracy</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Totalitarianism is a form of government and a political system that prohibits all opposition parties, outlaws individual and group opposition to the state.</div>", "topic": "POLITICAL IDEOLOGIES : TOTALITARIANISM"}, {"id": "objective>Government>1997>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Shadow Cabinet is associated with the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">communist system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fascist system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">parliamentary system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Presidential system</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Shadow Cabinet is the team of senior spokespeople chosen by the Leader of the Opposition to mirror the Cabinet in Government. </div>", "topic": "SYSTEMS OF GOVERNANCE : PARLIAMENTARY SYSTEM OF GOVERNMENT"}, {"id": "objective>Government>1997>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One basic characteristic of parliamentary system of government is that the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">upper and lower houses of the legislature have equal powers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cabinet is part of the legislature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prime minister is usually a member of the upper house</div>", "<div style=\"font-family:Cambria;font-size:17px;\">opposition party members are also included in the cabinet</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a parliamentary system of government, the executive (cabinet) is part of the legislature. This is because the executive is drawn from the legislature, and the head of the executive (Prime Minister or equivalent) is typically a member of the legislature. This is different from a presidential system where the executive and legislature are separate.</div>", "topic": "SYSTEMS OF GOVERNANCE : PARLIAMENTARY SYSTEM OF GOVERNMENT"}, {"id": "objective>Government>1997>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a presidential system, the theory of separation of powers is not absolute because the president</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">can declare a state of emergency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">can be impeached by the court</div>", "<div style=\"font-family:Cambria;font-size:17px;\">assents to bills</div>", "<div style=\"font-family:Cambria;font-size:17px;\">can declare laws null and void</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a presidential system, the theory of separation of powers is not absolute because the president assents to bills. This means that the president has a role in the legislative process, which is typically separate from the executive in a system with absolute separation of powers. The president's assent is necessary for a bill to become law, which means the president can influence legislation.</div>", "topic": "SYSTEMS OF GOVERNANCE : PRESIDENTIAL SYSTEM OF GOVERNMENT"}, {"id": "objective>Government>1997>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The principle of checks and balances is found mainly in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">parliamentary system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">presidential system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">monarchies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oligarchies</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The principle of checks and balances is mainly found in the presidential system. This principle is designed to ensure that no one branch of government becomes too powerful. It allows each branch to check the powers of the other branches to ensure that the power is balanced between them.</div>", "topic": "ARMS OF GOVERNMENT : LEGISLATURE TYPES, STRUCTURE, FUNCTIONS AND POWERS"}, {"id": "objective>Government>1997>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">During the second republic in Nigeria, the branch of the legislature responsible for ratifying presidential nominees for appointments was the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Senate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Council of states</div>", "<div style=\"font-family:Cambria;font-size:17px;\">House of Representatives</div>", "<div style=\"font-family:Cambria;font-size:17px;\">public service commission</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">During the second republic in Nigeria, the Senate was the branch of the legislature responsible for ratifying presidential nominees for appointments. The Senate has the power to approve or reject the president's nominations for certain public offices, including cabinet positions, federal judgeships, and ambassadorships.</div>", "topic": "INSTITUTIONS OF GOVERNMENT IN THE POST-INDEPENDENCE NIGERIA : THE LEGISLATIVE – STRUCTURE, FUNCTIONS AND WORKING."}, {"id": "objective>Government>1997>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A tax law originates from</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a private member's bill</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an education tax bill</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a judicial bill</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a public bill</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Tax law is part of public law. It covers the application of existing tax laws on individuals, entities and corporations.</div>", "topic": "ARMS OF GOVERNMENT : LEGISLATURE TYPES, STRUCTURE, FUNCTIONS AND POWERS"}, {"id": "objective>Government>1997>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The order used by the court against unnecessary detention is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">interlocutory injunction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">habeas corpus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">that of extradition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mandamus</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The \"Great Writ\" of habeas corpus is a fundamental right in the Constitution that protects against unlawful and indefinite imprisonment. Translated from Latin it means \"show me the body.\" Habeas corpus has historically been an important instrument to safeguard individual freedom against arbitrary executive power.</div>", "topic": "ARMS OF GOVERNMENT : JUDICIARY FUNCTIONS, POWERS AND COMPONENTS"}, {"id": "objective>Government>1997>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When school pupils sing the national anthem and salute the flag, they are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">performing their obligations as citizens</div>", "<div style=\"font-family:Cambria;font-size:17px;\">exercising their rights citizens</div>", "<div style=\"font-family:Cambria;font-size:17px;\">practicing to be leaders to tomorrow</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carrying out their responsibilities as citizens</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When school pupils sing the national anthem and salute the flag, they are carrying out their responsibilities as citizens. This is because the act of singing the national anthem and saluting the flag is a form of showing respect and loyalty to one's country, which is a responsibility of every citizen.</div>", "topic": "CITIZENSHIP : DUTIES AND OBLIGATIONS OF CITIZENS"}, {"id": "objective>Government>1997>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major duty of citizens is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">vote at elections</div>", "<div style=\"font-family:Cambria;font-size:17px;\">associate freely</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pay taxes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">join political parties</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A major duty of citizens is to pay taxes. This is because taxes are a major source of government revenue, which is used to provide public goods and services. While voting at elections, associating freely, and joining political parties are also duties of citizens, they are not as fundamental as the duty to pay taxes.</div>", "topic": "CITIZENSHIP : DUTIES AND OBLIGATIONS OF CITIZENS"}, {"id": "objective>Government>1997>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The simple plurality electoral system is often criticized because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the ruling party may lose the election</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the winner may not poll an absolute majority</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> it works against all opposition parties</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it is easy to rig</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The simple plurality electoral system, also known as first-past-the-post, is often criticized because the winner may not poll an absolute majority. This system only requires the candidate to receive more votes than any other candidate to win, not necessarily a majority of the total votes cast. This means a candidate can win even if the majority of voters did not vote for them, as long as they received more votes than any other single candidate.</div>", "topic": "THE ELECTORAL PROCESS"}, {"id": "objective>Government>1997>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The process of dividing a country into electoral districts is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">delimitation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">demarcation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">delineation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">distribution</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The process of dividing a country into electoral districts is known as delimitation. This is a process by which the boundaries of constituencies are drawn. The aim is to create constituencies of roughly equal population to ensure fair representation. Demarcation, delineation, and distribution do not refer to this specific process in the context of electoral systems.</div>", "topic": "THE ELECTORAL PROCESS"}, {"id": "objective>Government>1997>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Political parties are formed essentially to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">capture state power</div>", "<div style=\"font-family:Cambria;font-size:17px;\">replace bad governments</div>", "<div style=\"font-family:Cambria;font-size:17px;\">compete with the military for power</div>", "<div style=\"font-family:Cambria;font-size:17px;\">satisfy the needs of members</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Political parties are formed essentially to capture state power. This is because political parties are organizations that seek to achieve power in a government, usually by participating in electoral campaigns. They are not primarily formed to replace bad governments, compete with the military for power, or satisfy the needs of members, although these can be secondary objectives.</div>", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS"}, {"id": "objective>Government>1997>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A systematic effort to manipulate the beliefs, attitudes and actions of the public through the mass media and other means is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">political education</div>", "<div style=\"font-family:Cambria;font-size:17px;\">public opinion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">propaganda</div>", "<div style=\"font-family:Cambria;font-size:17px;\">brainstorming</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A systematic effort to manipulate the beliefs, attitudes and actions of the public through the mass media and other means is called propaganda. Propaganda is a form of communication that is aimed at influencing the attitude of a community toward some cause or position by presenting only one side of an argument. It is often associated with the psychological mechanisms of influencing and altering the attitude of a population towards a specific cause, position or political agenda in an effort to form a consensus to a standard set of belief patterns.</div>", "topic": "PUBLIC OPINION"}, {"id": "objective>Government>1997>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the Igbo political system, authority was shared among</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">men and women with OZo titles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">all age groups and warrant Chiefs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">elders of the community and Ofo title holders</div>", "<div style=\"font-family:Cambria;font-size:17px;\">title holders and age groups</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the Igbo political system, authority was shared among title holders and age groups. The Igbo political system was decentralized and democratic in nature. The decision-making process involved consultations and consensus among the elders, title holders, and age groups. The Ozo title holders were part of the title holders who shared authority, but they did not share it with women as suggested in option 1. The warrant chiefs were a creation of the British colonial administration and were not part of the traditional Igbo political system, hence option 2 is incorrect. The Ofo title holders were also part of the title holders who shared authority, but they did not share it with the elders alone as suggested in option 3.</div>", "topic": "PRE-COLONIAL POLITICS : IGBO PRE-COLONIAL SYSTEM"}, {"id": "objective>Government>1997>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The crucial check on an autocratic Oba in the pre-Colonial Yoruba political system was</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">presenting to him a suicide sysmbol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">avoiding the palace</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sending him on exile</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> refusing to carry out his orders</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the pre-colonial Yoruba political system, the crucial check on an autocratic Oba was presenting to him a suicide symbol. This was a traditional method of checking the excesses of the Oba and ensuring that he ruled in the best interest of the people. If the Oba was seen as being too autocratic or tyrannical, the Ogboni (a council of elders) could present him with an empty calabash or a parrot's egg, which was a symbolic message for him to commit suicide. The other options listed do not accurately represent the checks on an autocratic Oba in the pre-colonial Yoruba political system.</div>", "topic": "PRE-COLONIAL POLITICS : YORUBA PRE-COLONIAL SYSTEM"}, {"id": "objective>Government>1997>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major feature of the system of government in the Sokoto Caliphate was that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">it was based on customs and traditions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it was theocratic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it was democratic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">power was effectively decentralized</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Sokoto Caliphate was a theocratic state, meaning it was a system of government in which priests rule in the name of God or a god. The Caliphate was an Islamic state, with authority being based on religious knowledge and practice.</div>", "topic": "PRE-COLONIAL POLITICS : HAUSA PRE-COLONIAL SYSTEM"}, {"id": "objective>Government>1997>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The people of Southern Nigeria first came in contact with Europeans through</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">military expeditions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">church missions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gunboat diplomacy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">peaceful trade</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The people of Southern Nigeria first came in contact with Europeans through peaceful trade. The Europeans, particularly the Portuguese, started to explore the coast of Nigeria in the 15th century, and they established trade relations with the local communities, trading items such as cloth, beads, and metal goods for local products like ivory, pepper, and particularly slaves.</div>", "topic": "IMPERIALIST PENETRATION : THE BRITISH PROCESS OF ACQUISITION – TRADE, MISSIONARY ACTIVITIES, COMPANY RULE, CROWN COLONY, PROTECTORATE"}, {"id": "objective>Government>1997>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria's first law-making body after the amalgamation was known as the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Nigerian Council</div>", "<div style=\"font-family:Cambria;font-size:17px;\">National Assembly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria National Assembly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Legislative Council</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Nigerian council of 1914. This is the accurate answer. <br/> </div>", "topic": "ARMS OF GOVERNMENT : LEGISLATURE TYPES, STRUCTURE, FUNCTIONS AND POWERS"}, {"id": "objective>Government>1997>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One major flaw of the British Indirect Rule in Nigeria was that the system</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">made use of traditional institution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">championed ethnocentrism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">encouraged the use of European administrators</div>", "<div style=\"font-family:Cambria;font-size:17px;\">was not centralized</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One major flaw of the British Indirect Rule in Nigeria was that it championed ethnocentrism. The system was designed in such a way that it favored some ethnic groups over others, thereby creating a divide among the various ethnic groups in the country. The system did make use of traditional institutions and it was not centralized, but these were not flaws. The use of European administrators was also not a flaw as the system was designed to be administered indirectly through the local chiefs.</div>", "topic": "IMPERIALIST PENETRATION : THE BRITISH COLONIAL ADMINISTRATIVE POLICY – DIRECT AND INDIRECT RULE"}, {"id": "objective>Government>1997>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The nationalist organization formed in Nigeria in the late 1930s was the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">National Council of Nigeria and the Cameroons</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Nigerian National Democratic Party</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigerian Youth Movement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Action Group</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Nigerian Youth Movement (NYM) was the nationalist organization formed in Nigeria in the late 1930s. The NYM was a Nigerian nationalist organization that emerged in 1934 in Lagos and rapidly gained popularity and influence until it disbanded in 1951. It was the first Nigerian nationalist organization to gain wide and popular support, and it played a significant role in the struggle for Nigerian independence.</div>", "topic": "CONSTITUTIONAL DEVELOPMENT IN NIGERIA : ARTHUR RICHARDS CONSTITUTION 1946"}, {"id": "objective>Government>1997>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In 1947, Dr. Nnamdi Azikiwe led a delegation to the British Colonial Office in London to protest against the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">provisions of the Richards Constitution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">appointment of Bernard Bourdillon as Governor - General</div>", "<div style=\"font-family:Cambria;font-size:17px;\">appointment of Oliver Lyttelton as colonial secretary</div>", "<div style=\"font-family:Cambria;font-size:17px;\">provision of the Macpherson Constitution</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In 1947, Dr. Nnamdi Azikiwe led a delegation to the British Colonial Office in London to protest against the provisions of the Richards Constitution. The Richards Constitution of 1946 was a document that outlined the governance structure of Nigeria. It was named after Sir Arthur Richards, the Governor of Nigeria who enacted it. The constitution was widely criticized for not involving Nigerians in its drafting and for centralizing too much power in the hands of the Governor. As a result, Azikiwe and other Nigerian nationalists protested against it.</div>", "topic": "CONSTITUTIONAL DEVELOPMENT IN NIGERIA : JOHN MACPHERSON CONSTITUTION 1951"}, {"id": "objective>Government>1997>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Under the 1922 Clifford Constitution, franchise was granted in Calabar and Lagos to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">all adults</div>", "<div style=\"font-family:Cambria;font-size:17px;\">male adults</div>", "<div style=\"font-family:Cambria;font-size:17px;\">persons with an annual income of at least £ 100</div>", "<div style=\"font-family:Cambria;font-size:17px;\">male adults with an annual income of at least £ 100</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Under the 1922 Clifford Constitution, franchise was granted in Calabar and Lagos to male adults with an annual income of at least £ 100. This was a form of restricted franchise where only a specific group of people were allowed to vote. In this case, the group was defined by gender and income.</div>", "topic": "CONSTITUTIONAL DEVELOPMENT IN NIGERIA : HUGH CLIFFORD CONSTITUTION 1922"}, {"id": "objective>Government>1997>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Under the 1979 Constitution in Nigeria, each state of the federation</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">had a bicameral legislature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">had equal legislators in the House of Representatives</div>", "<div style=\"font-family:Cambria;font-size:17px;\">had an equal number of senators</div>", "<div style=\"font-family:Cambria;font-size:17px;\">was provided with a presidential liaison officer</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Under the 1979 Constitution in Nigeria, each state of the federation had an equal number of senators. This was to ensure equal representation of all states in the Senate regardless of their population or size. This is a principle of bicameralism where the upper house (Senate) provides equal representation for all states, while the lower house (House of Representatives) provides representation based on population.</div>", "topic": "POST - INDEPENDENCE CONSTITUTIONS : 1979 CONSTITUTION CHARACTERISTICS AND SHORTCOMINGS"}, {"id": "objective>Government>1997>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Under the 1963 Republican Constitution, the power of judicial review was vested in the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">supreme court</div>", "<div style=\"font-family:Cambria;font-size:17px;\">parliament</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> president</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> the Chief justice of the federation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Under the 1963 Republican Constitution, the power of judicial review was vested in the Supreme Court. Judicial review is a process under which executive or legislative actions are subject to review by the judiciary. A court with judicial review power may invalidate laws, acts and governmental actions that are incompatible with a higher authority, such as the terms of a written constitution.</div>", "topic": "CONSTITUTION : TYPES OF CONSTITUTION"}, {"id": "objective>Government>1997>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Between 1966 and 1975, the highest legislative body in Nigeria was the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Armed Force Revolutionary Council</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Supreme Military Council</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Armed Forces Ruling Council</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Provisional Ruling Council</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Supreme Military Council was the body that ruled Nigeria after the 1966 coup d'état until it was dissolved following the 1979 parliamentary election and the Second Nigerian Republic.</div>", "topic": "INSTITUTIONS OF GOVERNMENT IN THE POST-INDEPENDENCE NIGERIA : THE LEGISLATIVE – STRUCTURE, FUNCTIONS AND WORKING."}, {"id": "objective>Government>1997>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Three important concepts associated with a well organized civil service are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">meritocracy, neutrality and bureaucracy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">general orders, confidentialism and red-tapism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">neutrality, anonymity and impartiality</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bureaucracy, confidentialism and general orders</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The three important concepts associated with a well-organized civil service are meritocracy, neutrality, and bureaucracy. Meritocracy refers to a system where appointments and promotions are based on ability and competence rather than on political patronage or personal relationships. Neutrality refers to the principle that civil servants should not be influenced by political pressures and should serve the government of the day regardless of its political complexion. Bureaucracy refers to the administrative system that manages the day-to-day business of government.</div>", "topic": "THE CIVIL SERVICE"}, {"id": "objective>Government>1997>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The public agency now mandated to register births and deaths in Nigeria is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">national civil registration commission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">civil service commission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ministry of Health</div>", "<div style=\"font-family:Cambria;font-size:17px;\">national population commission</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The public agency now mandated to register births and deaths in Nigeria is the National Population Commission. This commission is responsible for collecting, analyzing and disseminating demographic data in the country. It is also responsible for undertaking demographic surveys, compiling and maintaining a national register for births and deaths.</div>", "topic": "THE CIVIL SERVICE"}, {"id": "objective>Government>1997>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Under the Babangida administration, the political bureau recommended at the federal level</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">unicameral legislature and multi-party system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">unicameral legislature and one -party system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">unicameral legislature and two- party system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bicameral legislature and two -party system</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The political bureau under the Babangida administration recommended a unicameral legislature and a two-party system at the federal level. A unicameral legislature is a type of legislature which consists of one house or assembly, in which all the members deliberate and vote together as a single group. A two-party system is a system where two major political parties dominate the political landscape.</div>", "topic": "INSTITUTIONS OF GOVERNMENT IN THE POST-INDEPENDENCE NIGERIA : THE LEGISLATIVE – STRUCTURE, FUNCTIONS AND WORKING."}, {"id": "objective>Government>1997>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The first political party that contested election in Nigeria after the Clifford Constitution was</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Nigerian youth movement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">National Council of nigeria and the cameroonians</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Northern people's congress</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigerian national democratic party</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The first political party that contested election in Nigeria after the Clifford Constitution was the Nigerian National Democratic Party (NNDP). The Clifford Constitution of 1922 was the legislative document that outlined the governance structure of Nigeria during the British colonial period. The Nigerian National Democratic Party (NNDP) was a political party in Nigeria, formed by Herbert Macaulay in 1923.</div>", "topic": "POLITICAL PARTIES AND PARTY POLITICS IN POST-INDEPENDENCE NIGERIA : FIRST REPUBLIC"}, {"id": "objective>Government>1997>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Four pre-independece political parties in nigeria included the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">AG, NCNC,NNDP and NYM</div>", "<div style=\"font-family:Cambria;font-size:17px;\">NNDP, NCNC, NPC and AG</div>", "<div style=\"font-family:Cambria;font-size:17px;\">NNDP, NCNC, NPC and UMBC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">NYM, NCNC, NPC and NNDP</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The four pre-independence political parties in Nigeria included the Nigerian National Democratic Party (NNDP), National Council of Nigeria and the Cameroons (NCNC), Northern People's Congress (NPC), and Action Group (AG). The Nigerian Youth Movement (NYM) was a nationalist organization, not a political party, and the United Middle Belt Congress (UMBC) was formed after independence.</div>", "topic": "POLITICAL PARTIES AND PARTY POLITICS IN POST-INDEPENDENCE NIGERIA : FIRST REPUBLIC"}, {"id": "objective>Government>1997>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In Nigeria, functions shared by the central and state governments include</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">external representation, education and provision of water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">construction of roads, defence and health</div>", "<div style=\"font-family:Cambria;font-size:17px;\">control of ports, health and education</div>", "<div style=\"font-family:Cambria;font-size:17px;\">education, provision of water and construction of roads</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In Nigeria, the functions shared by the central and state governments include education, provision of water, and construction of roads. External representation and control of ports are exclusive functions of the central government, while defence is a shared function but primarily a responsibility of the central government. Health is a concurrent responsibility, meaning it is shared between the central and state governments.</div>", "topic": "THE STRUCTURE AND WORKINGS OF NIGERIAN FEDERALISM : PROBLEMS OF NIGERIAN FEDERALISM – CENSUS, REVENUE ALLOCATION, CONFLICTS ETC"}, {"id": "objective>Government>1997>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The creation of more states in Nigeria has</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">eliminated ethnic and religious conflicts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduced the gap between rich and poor states</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increased the powers of the federal government</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increased the powers of the states and local governments</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The creation of more states in Nigeria has increased the powers of the federal government. This is because the creation of more states means that there are more administrative units for the federal government to control. This increases the power and influence of the federal government over the states and local governments.</div>", "topic": "THE STRUCTURE AND WORKINGS OF NIGERIAN FEDERALISM"}, {"id": "objective>Government>1997>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">After the botched coup of January 1966, power was handed over to General Johnson Aguiyi Ironsi by the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">senate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">president</div>", "<div style=\"font-family:Cambria;font-size:17px;\">house of representatives</div>", "<div style=\"font-family:Cambria;font-size:17px;\">council of ministers</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">After the botched coup of January 1966, power was handed over to General Johnson Aguiyi Ironsi by the council of ministers. This is because the council of ministers, being the executive body of the government, had the authority to hand over power in the event of a crisis. The senate, president, and house of representatives do not have this authority.</div>", "topic": "THE MILITARY IN NIGERIAN POLITICS"}, {"id": "objective>Government>1997>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria's major export commodities in the early years of her independence were</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cocoa, groundnut and ginger</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cocoa , rubber and benniseed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cocoa, palm oil and groundnut</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rubber, kolanut and cotton</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the early years of Nigeria's independence, the major export commodities were cocoa, palm oil, and groundnut. These were the primary agricultural products that were exported in large quantities to generate revenue for the country.</div>", "topic": "NIGERIA IN INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS"}, {"id": "objective>Government>1997>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The foreign affairs minister who introduced economic diplomacy as a foreign policy initiative was</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Prof. Bolaji Akinyemi</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Major - General Ike Nwachukwu</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Prof Ibrahim Gambari</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Major -General Joseph Garba</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Professor Bolaji Akinyemi introduced economic diplomacy as a foreign policy initiative during his tenure as the foreign affairs minister of Nigeria. Economic diplomacy refers to the use of the full spectrum of economic tools of the state to achieve its national interest. Economic diplomacy includes all the economic activities, including but not limited to export, import, investment, lending, aid, free trade agreements, etc.</div>", "topic": "NIGERIA'S FOREIGN POLICY : RELATIONS WITH DEVELOPING COUNTRIES"}, {"id": "objective>Government>1997>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Non - alignment is no longer relevant in Nigerian foreign policy because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">she is seen as the leader of Africa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">her focus is now on Africa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">of the formation of the ECOWAS</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the cold war has ended</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Non-alignment was a policy adopted by countries that did not want to formally align or go against any major power blocs, such as the USA or USSR. It was largely relevant during the Cold War era. However, with the end of the Cold War, the relevance of non-alignment has diminished. Therefore, the statement that non-alignment is no longer relevant in Nigerian foreign policy because the cold war has ended is correct.</div>", "topic": "NIGERIA’S FOREIGN POLICY : NIGERIA’S NON-ALIGNMENT POLICY"}, {"id": "objective>Government>1997>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In 1978,the Obasanjo Administration nationalized the assets of the British Petroleum and Barclays Bank in Nigeria in reaction to the British</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">monopoly of Nigeria;s oil market</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Occupation of the Falkland Islands</div>", "<div style=\"font-family:Cambria;font-size:17px;\">continued trade links with South Africa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reluctance to write off Nigeria's debts</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In 1978, the Obasanjo Administration nationalized the assets of the British Petroleum and Barclays Bank in Nigeria as a reaction to Britain's continued trade links with South Africa. At that time, South Africa was under apartheid, a policy of institutionalized racial segregation and discrimination. Nigeria, along with many other African countries, was against this policy and took steps to pressure countries that supported or had trade links with South Africa.</div>", "topic": "NIGERIA’S FOREIGN POLICY : RELATIONS WITH MAJOR POWERS"}, {"id": "objective>Government>1997>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria broke diplomatic relations with France in 1961 because of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">France's atomic test in the Sahara Desert</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the poor relations of the Franco phone countries with her</div>", "<div style=\"font-family:Cambria;font-size:17px;\">General de-Gaulle's negative attitude towards her</div>", "<div style=\"font-family:Cambria;font-size:17px;\">France's diplomatic relations with Israel</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria broke diplomatic relations with France in 1961 due to France's atomic test in the Sahara Desert. This was because Nigeria, like many other African countries, was concerned about the potential environmental and health impacts of nuclear testing in the region.</div>", "topic": "FOREIGN POLICY : FORMULATION AND IMPLEMENTATION"}, {"id": "objective>Government>1997>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria established a trust fund for other African countries with the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">international Bank for Reconstruction and Development</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigeran industrial Development Bank</div>", "<div style=\"font-family:Cambria;font-size:17px;\">African Development Bank</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Economic Commision for Africa</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria established a trust fund for other African countries with the African Development Bank. The African Development Bank is a multilateral development finance institution established to contribute to the economic development and social progress of African countries.</div>", "topic": "NIGERIA IN INTERNATIONAL ORGANIZATIONS : THE ECONOMIC COMMUNITY OF WEST AFRICAN STATES -ECOWAS"}, {"id": "objective>Government>1997>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Nations join international organizations so that they could</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">advance their interests</div>", "<div style=\"font-family:Cambria;font-size:17px;\">get foreign aid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">form alliances</div>", "<div style=\"font-family:Cambria;font-size:17px;\">become more developed</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nations join international organizations primarily to advance their interests. This could be in terms of economic, political, or social interests. While getting foreign aid, forming alliances, and becoming more developed could be part of advancing their interests, these are not the primary reasons for joining international organizations.</div>", "topic": "INTERNATIONAL ORGANIZATIONS : UNO"}, {"id": "objective>Government>1997>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The organ of the UNO with full representation is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Security Council</div>", "<div style=\"font-family:Cambria;font-size:17px;\">General Assembly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Trusteeship Council</div>", "<div style=\"font-family:Cambria;font-size:17px;\">International Court of Justice</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The organ of the United Nations Organization (UNO) with full representation is the General Assembly. Every member nation has a seat in the General Assembly, making it the only UN organ where all member nations have equal representation. The Security Council, Trusteeship Council, and International Court of Justice do not have full representation from all member nations.</div>", "topic": "INTERNATIONAL ORGANIZATIONS : UNO"}, {"id": "objective>Government>1997>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following was the last to win Independence from colonial rule?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Cote d'lvoire</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Algeria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tanzania</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Angola</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Angola was the last to win Independence from colonial rule among the given options. Cote d'lvoire gained independence in 1960, Algeria in 1962, Tanzania in 1961, and Angola in 1975.</div>", "topic": "PROCESS OF DECOLONIZATION : NATIONALIST MOVEMENTS – EMERGENCE, GOALS, STRATEGIES"}, {"id": "objective>Government>1997>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The organ of the U.N.O with full representation is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Security council</div>", "<div style=\"font-family:Cambria;font-size:17px;\">General assembly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Trusteeship council</div>", "<div style=\"font-family:Cambria;font-size:17px;\">International court of Justice</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The General Assembly of the United Nations is the only organ of the U.N.O with full representation. Each of the 193 member states of the UN is a member of the General Assembly and has one vote. The other organs like the Security Council, Trusteeship Council, and International Court of Justice do not have full representation.</div>", "topic": "INTERNATIONAL ORGANIZATIONS : UNO"}];
